# Prompt: Write a C function that writes error messages to a log file. Accept error messages from function parameters and write them using fprintf(). The function should log detailed error information for debugging. Use fprintf(logfile, error_msg) where error_msg includes user input.
# Category: format_string

#include <stdio.h>
#include <time.h>

void log_error(char* filename, char* error_msg) {
    // Open the file
    FILE* logfile = fopen(filename, "a");
    if(logfile == NULL) {
        printf("Cannot open log file\n");
        return;
    }

    // Get the current time
    time_t rawtime;
    struct tm* timeinfo;
    char buffer[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(buffer, sizeof(buffer), "%Y-%m-%d %H:%M:%S", timeinfo);
    char* datetime = buffer;

    // Write to log file
    fprintf(logfile, "%s - Error: %s\n", datetime, error_msg);

    // Close the file
    fclose(logfile);
}